var assert=require("assert");describe("fs",function(){var t=require("../");it(".stat()",function(e){t.stat(__filename).then(function(t){assert.equal(typeof t.size,"number"),e()}).catch(e)}),it(".statSync()",function(){var e=t.statSync(__filename);assert.equal(typeof e.size,"number")}),it(".exists()",function(e){t.exists(__filename).then(function(t){assert(t),e()}).catch(e)}),it(".existsSync()",function(){var e=t.existsSync(__filename);assert(e)}),describe("callback support",function(){it(".stat()",function(e){t.stat(__filename,function(t,s){assert(!t),assert.equal(typeof s.size,"number"),e()})}),it(".exists()",function(e){t.exists(__filename,function(t,s){assert(!t),assert(s),e()})})})});